})

const hasValidTraits = computed(() => {
  const traits = displayTraits.value
  if (!traits || traits.length === 0) return false
  return traits.some(trait => trait && trait.trim() !== '' && trait !== '待补充')
})

// ============================================================
// 日用常行
// ============================================================
const displayDailyPractice = computed(() => {
